55	        /// The name for this resource provider.
56	        /// For instance, if the namespace is "Azure.ResourceManager.Compute", the resource provider name will be "Compute".
57	        /// </summary>
58	        public string ResourceProviderName => _resourceProviderName ??= BuildResourceProviderName();
