235	        /// <summary>
236	        /// Demonstrates that ArmResource.GetCachedClient uses typeof(T) as cache key,
237	        /// so different parameter values captured in the factory closure are silently ignored
238	        /// after the first call. This means parameterized collection getters that use
239	        /// GetCachedClient will return stale instances when called with different path parameters.
240	        /// </summary>
241	        [TestCase]
242	        public void Verify_GetCachedClient_IgnoresParameterChanges()
243	        {
244	            // ArmResource._clientCache is ConcurrentDictionary<Type, object>
245	            // GetCachedClient<T> calls: _clientCache.GetOrAdd(typeof(T), _ => clientFactory(Client))
246	            // This means the cache key is ONLY the type T, not the parameters.
247	
248	            // Simulate the exact same caching mechanism used by ArmResource.GetCachedClient
249	            var cache = new System.Collections.Concurrent.ConcurrentDictionary<System.Type, object>();
250	
251	            // First call with nestedTypeName = "typeA"
252	            var collection1 = cache.GetOrAdd(typeof(FakeCollection), _ => new FakeCollection("typeA")) as FakeCollection;
253	
254	            // Second call with nestedTypeName = "typeB" — expects a DIFFERENT collection
255	            var collection2 = cache.GetOrAdd(typeof(FakeCollection), _ => new FakeCollection("typeB")) as FakeCollection;
256	
257	            // BUG: Both return the same instance — the second parameter is silently ignored
258	            Assert.AreSame(collection1, collection2, "GetCachedClient returns the same instance regardless of parameter values");
259	            Assert.AreEqual("typeA", collection2!.NestedTypeName,
260	                "Second call should have nestedTypeName='typeB' but got 'typeA' because GetCachedClient ignores the closure parameters after first call");

